exercises.canonical_solution:
def max_product(s):
    if not s:
        return 1
    if len(s) == 1:
        return s[0]
    n = len(s)
    dp = [1] * (n + 2)
    for i in range(n - 1, -1, -1):
        dp[i] = max(s[i] * dp[i + 2], dp[i + 1])
    return dp[0]
